head.script:
window.dataLayer = window.dataLayer || [];
function gtag() {
    dataLayer.push(arguments);
}
gtag("js", new Date());
gtag("config", "G-0VL3ZSBXDH");

main.style:
min-height: 100vh;
display: grid;
place-content: center;
padding: 2rem;
text-align: center;
font-family: Manrope, "Segoe UI", sans-serif;
color: #1e2a27;
background: linear-gradient(180deg, #f9f4ec 0%, #f3ece1 50%, #efe6da 100%);

span.style:
display: inline-block;
padding: 6px 14px;
border-radius: 999px;
background: rgba(201, 109, 58, 0.14);
color: #a55428;
font-size: 0.85rem;
font-weight: 600;
letter-spacing: 0.02em;
margin-bottom: 1rem;
